import _pickle as cPickle
import base64

def confirmAuth(headers):
    auth_token = headers.get('AuthToken', '')
    try:
        decoded = base64.b64decode(auth_token)
        token_obj = cPickle.loads(decoded)
        if token_obj.get('valid', False):
            return token_obj.get('data')
        return None
    except (base64.binascii.Error, cPickle.UnpicklingError, EOFError, AttributeError):
        return None

import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('AuthToken', '')
    try:
        decoded = base64.b64decode(auth_token)
        token_obj = json.loads(decoded.decode('utf-8'))
        if token_obj.get('valid', False):
            return token_obj.get('data')
        return None
    except (base64.binascii.Error, json.JSONDecodeError, UnicodeDecodeError):
        return None

